def stratify(chunks: list[dict], n: int, seed: int = 0) -> list[dict]:
    """Pick n chunks with roughly balanced language coverage."""
    rng = random.Random(seed)
    by_lang: dict[str, list[dict]] = defaultdict(list)
    for c in chunks:
        by_lang[c["language"]].append(c)
    langs = list(by_lang.keys())
    rng.shuffle(langs)
    picked: list[dict] = []
    # Round-robin across languages.
    cursor = {lang: 0 for lang in langs}
    idx_lang = {lang: 0 for lang in langs}
    for lang in langs:
        rng.shuffle(by_lang[lang])
    while len(picked) < n and langs:
        progress = False
        for lang in langs:
            if idx_lang[lang] < len(by_lang[lang]):
                picked.append(by_lang[lang][idx_lang[lang]])
                idx_lang[lang] += 1
                progress = True
                if len(picked) >= n:
                    break
        if not progress:
            break
    return picked

impl PartialOrd for OrderedFloat {
    /// Compares two values and returns an ordering, wrapped in `Option`.
    ///
    /// # Arguments
    ///
    /// * `other` - The value to compare against
    ///
    /// # Returns
    ///
    /// Returns `Some(Ordering)` indicating whether `self` is less than, equal to, or greater than `other`.
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }

impl Ord for OrderedFloat {
    /// Compares two values using total ordering on their inner floating-point values.
    ///
    /// # Arguments
    ///
    /// * `other` - The value to compare against
    ///
    /// # Returns
    ///
    /// An `Ordering` indicating whether `self` is less than, equal to, or greater than `other`. Uses total ordering semantics where NaN values are comparable.
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.0.total_cmp(&other.0)
    }
}

