pub(in crate::cli::batch) fn dispatch_suggest(
    ctx: &BatchContext,
    apply: bool,
) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_suggest", apply).entered();

    let suggestions = cqs::suggest::suggest_notes(&ctx.store(), &ctx.root)?;

    if apply && !suggestions.is_empty() {
        let notes_path = ctx.root.join("docs/notes.toml");
        let entries: Vec<cqs::NoteEntry> = suggestions
            .iter()
            .map(|s| cqs::NoteEntry {
                sentiment: s.sentiment,
                text: s.text.clone(),
                mentions: s.mentions.clone(),
            })
            .collect();
        cqs::rewrite_notes_file(&notes_path, |notes| {
            notes.extend(entries);
            Ok(())
        })?;
        let notes = cqs::parse_notes(&notes_path)?;
        cqs::index_notes(&notes, &notes_path, &ctx.store())?;
    }

    let json_val: Vec<_> = suggestions
        .iter()
        .map(|s| {
            serde_json::json!({
                "text": s.text,
                "sentiment": s.sentiment,
                "mentions": s.mentions,
                "reason": s.reason,
            })
        })
        .collect();

    Ok(serde_json::json!({
        "suggestions": json_val,
        "total": suggestions.len(),
        "applied": apply,
    }))
}

pub fn find_hotspots(graph: &CallGraph, top_n: usize) -> Vec<crate::health::Hotspot> {
    let _span = tracing::info_span!("find_hotspots", top_n).entered();

    let mut hotspots: Vec<crate::health::Hotspot> = graph
        .reverse
        .iter()
        .map(|(name, callers)| crate::health::Hotspot {
            name: name.to_string(),
            caller_count: callers.len(),
        })
        .collect();
    hotspots.sort_by(|a, b| b.caller_count.cmp(&a.caller_count));
    hotspots.truncate(top_n);
    hotspots
}

pub(in crate::cli::batch) fn dispatch_notes(
    ctx: &BatchContext,
    warnings: bool,
    patterns: bool,
) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_notes", warnings, patterns).entered();

    let notes = ctx.notes();
    let filtered: Vec<_> = notes
        .iter()
        .filter(|n| {
            if warnings {
                n.is_warning()
            } else if patterns {
                n.is_pattern()
            } else {
                true
            }
        })
        .map(|n| {
            serde_json::json!({
                "text": n.text,
                "sentiment": n.sentiment,
                "sentiment_label": n.sentiment_label(),
                "mentions": n.mentions,
            })
        })
        .collect();

    Ok(serde_json::json!({
        "notes": filtered,
        "total": filtered.len(),
    }))
}

fn detect_stale_mentions(store: &Store, root: &Path) -> Result<Vec<SuggestedNote>, StoreError> {
    let stale_pairs = find_stale_mentions(store, root)?;

    Ok(stale_pairs
        .into_iter()
        .map(|(text, stale)| {
            let preview = if text.len() > 80 {
                format!("{}...", &text[..text.floor_char_boundary(77)])
            } else {
                text
            };
            SuggestedNote {
                text: format!(
                    "Note has stale mentions [{}]: \"{}\"",
                    stale.join(", "),
                    preview,
                ),
                sentiment: -0.5,
                mentions: stale,
                reason: "stale_mention".to_string(),
            }
        })
        .collect())
}

async fn migrate_v17_to_v18(conn: &mut sqlx::SqliteConnection) -> Result<(), StoreError> {
    let _span = tracing::info_span!("migrate_v17_to_v18").entered();

    sqlx::query("ALTER TABLE chunks ADD COLUMN embedding_base BLOB")
        .execute(&mut *conn)
        .await?;

    tracing::info!("Migrated to v18: embedding_base column (NULL until next index pass)");
    Ok(())
}

pub fn callable_sql_list() -> String {
        Self::ALL
            .iter()
            .filter(|ct| ct.is_callable())
            .map(|ct| {
                let s = ct.to_string();
                // SEC-13: Guard against SQL injection if a future variant name contains quotes
                debug_assert!(!s.contains('\''), "ChunkType display contains quote: {s}");
                format!("'{}'", s)
            })
            .collect::<Vec<_>>()
            .join(",")
    }

pub fn prune_orphan_sparse_vectors(&self) -> Result<usize, StoreError> {
        let _span = tracing::debug_span!("prune_orphan_sparse_vectors").entered();
        self.rt.block_on(async {
            let (_guard, mut tx) = self.begin_write().await?;
            let result = sqlx::query(
                "DELETE FROM sparse_vectors WHERE chunk_id NOT IN \
                 (SELECT DISTINCT id FROM chunks)",
            )
            .execute(&mut *tx)
            .await?;
            // If any rows were actually deleted, bump the SPLADE generation
            // so stale on-disk indexes get invalidated. A prune that removes
            // zero rows leaves sparse_vectors byte-identical, so the existing
            // generation is still valid and no bump is needed.
            let affected = result.rows_affected();
            if affected > 0 {
                bump_splade_generation_tx(&mut tx).await?;
                tracing::warn!(
                    rows = affected,
                    "prune_orphan_sparse_vectors deleted rows that should have been caught by \
                     the v19 FK cascade — either FK enforcement is disabled or this database was \
                     manipulated directly. Investigate."
                );
            }
            tx.commit().await?;
            Ok(affected as usize)
        })
    }

