def evaluate(queries, splade=False, label=""):
    """Evaluate queries and return per-query results."""
    r1 = r5 = found = total = 0
    by_cat = defaultdict(lambda: {"r1": 0, "r5": 0, "r20": 0, "n": 0})

    for q in queries:
        total += 1
        cat = q["category"]
        by_cat[cat]["n"] += 1

        results = run_search(q["query"], n=20, splade=splade)
        names = [r[0] for r in results]

        expected = q["primary_answer"]["name"]
        acceptable = [a["name"] for a in q.get("acceptable_answers", [])]
        all_valid = {expected} | set(acceptable)

        hit_at = None
        for i, name in enumerate(names):
            if name in all_valid:
                hit_at = i + 1
                break

        if hit_at is not None:
            found += 1
            by_cat[cat]["r20"] += 1
            if hit_at <= 5:
                r5 += 1
                by_cat[cat]["r5"] += 1
            if hit_at <= 1:
                r1 += 1
                by_cat[cat]["r1"] += 1

        if total % 10 == 0:
            print(f"  {label}: {total}/{len(queries)} queries...", file=sys.stderr)

    return {
        "r1": r1, "r5": r5, "r20": found, "n": total,
        "by_cat": dict(by_cat),
    }

fn eval_retrieval_quality() {
    let embedder = Embedder::new().unwrap();
    let store = Store::open("fixtures/eval_index.db").unwrap();

    let mut passed = 0;
    let mut failed = Vec::new();

    for eq in EVAL_QUERIES {
        let query_emb = embedder.embed_query(eq.query).unwrap();
        let results = store.search(&query_emb, 5, 0.0).unwrap();

        let found = results.iter().any(|r| r.chunk.name == eq.expected_name);
        if found {
            passed += 1;
        } else {
            failed.push((eq.query, eq.expected_name));
        }
    }

    let total = EVAL_QUERIES.len();
    let ratio = passed as f32 / total as f32;

    println!("Eval: {}/{} ({:.0}%)", passed, total, ratio * 100.0);
    for (query, expected) in &failed {
        println!("  FAIL: '{}' should find '{}'", query, expected);
    }

    assert!(ratio >= 0.8, "Retrieval quality below 80%: {}/{}", passed, total);
}

fn evaluate_gate(risk: &RiskSummary, threshold: GateThreshold) -> GateResult {
    let (passed, reasons) = match threshold {
        GateThreshold::High => {
            if risk.high > 0 {
                (
                    false,
                    vec![format!("{} high-risk function(s) detected", risk.high)],
                )
            } else {
                (true, Vec::new())
            }
        }
        GateThreshold::Medium => {
            let mut reasons = Vec::new();
            if risk.high > 0 {
                reasons.push(format!("{} high-risk function(s)", risk.high));
            }
            if risk.medium > 0 {
                reasons.push(format!("{} medium-risk function(s)", risk.medium));
            }
            (reasons.is_empty(), reasons)
        }
        GateThreshold::Off => (true, Vec::new()),
    };
    GateResult {
        threshold,
        passed,
        reasons,
    }
}

pub(crate) fn score_candidate(
    embedding: &[f32],
    name: Option<&str>,
    file_part: &str,
    ctx: &ScoringContext<'_>,
) -> Option<f32> {
    let base = cosine_similarity(ctx.query, embedding)?;
    apply_scoring_pipeline(base, name, file_part, ctx)
}

pub(crate) struct NameMatcher {
    query_lower: String,
    /// True if `query_lower` is pure ASCII — allows byte-wise case-insensitive
    /// comparisons with names, skipping `to_lowercase()` allocation entirely.
    query_is_ascii: bool,
    query_words: Vec<String>,
    /// True if every entry in `query_words` is pure ASCII. Used to gate the
    /// zero-alloc word-overlap path (which relies on byte-level comparisons).
    query_words_ascii: bool,
}

pub(crate) fn apply_scoring_pipeline(
    embedding_score: f32,
    name: Option<&str>,
    file_part: &str,
    ctx: &ScoringContext<'_>,
) -> Option<f32> {
    let base_score = if let Some(matcher) = ctx.name_matcher {
        let n = name.unwrap_or("");
        let name_score = matcher.score(n);
        (1.0 - ctx.filter.name_boost) * embedding_score + ctx.filter.name_boost * name_score
    } else {
        embedding_score
    };

    if let Some(matcher) = ctx.glob_matcher {
        if !matcher.is_match(file_part) {
            return None;
        }
    }

    let chunk_name = name.unwrap_or("");
    let mut score = base_score.max(0.0) * ctx.note_index.boost(file_part, chunk_name);

    if ctx.filter.enable_demotion {
        score *= chunk_importance(chunk_name, file_part);
    }

    if score >= ctx.threshold {
        Some(score)
    } else {
        None
    }
}

pub(crate) struct ScoringContext<'a> {
    pub query: &'a [f32],
    pub filter: &'a SearchFilter,
    pub name_matcher: Option<&'a NameMatcher>,
    pub glob_matcher: Option<&'a globset::GlobMatcher>,
    /// PF-V1.25-4: accepts either a freshly-built `NoteBoostIndex` borrowing
    /// from per-call notes, or a cached `Arc<OwnedNoteBoostIndex>` reused
    /// across searches. The `NoteBoost` enum dispatches at the call site.
    pub note_index: &'a super::note_boost::NoteBoost<'a>,
    pub threshold: f32,
}

