fn open(path: &Path) -> Result<Self> {
        let conn = Connection::open(path)?;

        // Enable WAL mode for better concurrent read performance
        conn.pragma_update(None, "journal_mode", "WAL")?;
        // Wait up to 5s if database is locked
        conn.pragma_update(None, "busy_timeout", 5000)?;
        // NORMAL sync is safe with WAL and faster than FULL
        conn.pragma_update(None, "synchronous", "NORMAL")?;

        let store = Self { conn };

        // Check schema version compatibility
        store.check_schema_version()?;
        // Check model version compatibility
        store.check_model_version()?;

        Ok(store)
    }

pub(crate) fn check_idle_timeout(&self) {
        self.sweep_idle_sessions();
        self.last_command_time.set(Instant::now());
    }

pub(crate) fn sweep_idle_sessions(&self) {
        let timeout_minutes = idle_timeout_minutes();
        if timeout_minutes == 0 {
            return;
        }
        let elapsed = self.last_command_time.get().elapsed();
        let timeout = std::time::Duration::from_secs(timeout_minutes * 60);
        if elapsed < timeout {
            return;
        }
        if let Some(emb) = self.embedder.get() {
            emb.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared embedder session after idle timeout"
            );
        }
        if let Some(rr) = self.reranker.get() {
            rr.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared reranker session after idle timeout"
            );
        }
        // RM-3: Also clear SPLADE encoder session
        if let Some(splade) = self.splade_encoder.get().and_then(|opt| opt.as_ref()) {
            splade.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared SPLADE session after idle timeout"
            );
        }
    }

pub fn describe_command(args: &[String]) -> (String, Option<String>) {
    use clap::CommandFactory;

    // args[0] is the binary name
    let cmd = args.get(1).map(|s| s.as_str()).unwrap_or("unknown");

    // If it's a bare query (no subcommand), it's a search
    if !cmd.starts_with('-') && !cmd.is_empty() {
        // Check if it's a known subcommand by querying clap's registry.
        // Also recognizes "help" which clap adds automatically.
        let clap_app = super::definitions::Cli::command();
        let is_subcommand = clap_app.get_subcommands().any(|sc| sc.get_name() == cmd);

        if is_subcommand {
            // It's a subcommand -- look for query in remaining args
            let query = args.iter().skip(2).find(|a| !a.starts_with('-')).cloned();
            return (cmd.to_string(), query);
        }

        // Bare query -- it's a search
        return ("search".to_string(), Some(cmd.to_string()));
    }

    (cmd.to_string(), None)
}

