    // JSON has no functions or return types
    None
}

fn extract_return_swift(signature: &str) -> Option<String> {
    // Swift: func name(params) -> ReturnType {
    // Find "->" and extract the type between it and "{"
    let arrow_pos = signature.find("->")?;
    let after_arrow = &signature[arrow_pos + 2..];

    let end_pos = after_arrow.find('{').unwrap_or(after_arrow.len());
    let ret_type = after_arrow[..end_pos].trim();

    if ret_type.is_empty() || ret_type == "Void" {
        return None;
    }

    let ret_words = crate::nl::tokenize_identifier(ret_type).join(" ");
    Some(format!("Returns {}", ret_words))
}

pub(in crate::cli::batch) fn dispatch_dead(
    ctx: &BatchContext,
    include_pub: bool,
    min_confidence: &DeadConfidence,
) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_dead").entered();

    let (confident, possibly_pub) = ctx.store().find_dead_code(include_pub)?;

    let confident: Vec<_> = confident
        .into_iter()
        .filter(|d| d.confidence >= *min_confidence)
        .collect();
    let possibly_pub: Vec<_> = possibly_pub
        .into_iter()
        .filter(|d| d.confidence >= *min_confidence)
        .collect();

    let output = crate::cli::commands::build_dead_output(&confident, &possibly_pub, &ctx.root);
    Ok(serde_json::to_value(&output)?)
}

fn find_affected_tests_cross(
    ctx: &mut CrossProjectContext,
    visited: &HashMap<String, (usize, String)>,
) -> Result<Vec<TestInfo>, StoreError> {
    let _span = tracing::info_span!("find_affected_tests_cross").entered();
    let test_chunks = ctx.find_test_chunks_cross()?;

    let visited_names: HashSet<&str> = visited.keys().map(|s| s.as_str()).collect();

    let tests: Vec<TestInfo> = test_chunks
        .iter()
        .filter(|tc| visited_names.contains(tc.chunk.name.as_str()))
        .map(|tc| {
            let depth = visited.get(&tc.chunk.name).map(|(d, _)| *d).unwrap_or(0);
            TestInfo {
                name: tc.chunk.name.clone(),
                file: tc.chunk.file.clone(),
                line: tc.chunk.line_start,
                call_depth: depth,
            }
        })
        .collect();

    Ok(tests)
}

