extern "C" fn cleanup() {
            // Note: remove_file may allocate. This is acceptable for a CLI tool
            // that always exits normally. For shared library usage (theoretical),
            // this could deadlock if exit() is called from a signal handler.
            if let Ok(paths) = CLEANUP_PATHS.lock() {
                for path in paths.iter() {
                    if path.symlink_metadata().is_ok() && std::fs::read_link(path).is_ok() {
                        let _ = std::fs::remove_file(path);
                    }
                }
            }
        }

pub(crate) fn check_idle_timeout(&self) {
        self.sweep_idle_sessions();
        self.last_command_time.set(Instant::now());
    }

fn symlink_providers(src_dir: &Path, target_dir: &Path, libs: &[&str]) {
    for lib in libs {
        let src = src_dir.join(lib);
        let dst = target_dir.join(lib);

        if !src.exists() {
            continue;
        }

        // Skip if symlink already points to the right place.
        // Canonicalize both paths so relative vs absolute and symlink chains
        // don't cause false mismatches (PB-10).
        if let Ok(existing) = std::fs::read_link(&dst) {
            let existing_canon = dunce::canonicalize(&existing).unwrap_or(existing);
            let src_canon = dunce::canonicalize(&src).unwrap_or_else(|_| src.clone());
            if existing_canon == src_canon {
                continue;
            }
            let _ = std::fs::remove_file(&dst);
        }

        if let Err(e) = std::os::unix::fs::symlink(&src, &dst) {
            tracing::debug!("Failed to symlink {}: {}", lib, e);
        }
    }
}

pub(crate) fn sweep_idle_sessions(&self) {
        let timeout_minutes = idle_timeout_minutes();
        if timeout_minutes == 0 {
            return;
        }
        let elapsed = self.last_command_time.get().elapsed();
        let timeout = std::time::Duration::from_secs(timeout_minutes * 60);
        if elapsed < timeout {
            return;
        }
        if let Some(emb) = self.embedder.get() {
            emb.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared embedder session after idle timeout"
            );
        }
        if let Some(rr) = self.reranker.get() {
            rr.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared reranker session after idle timeout"
            );
        }
        // RM-3: Also clear SPLADE encoder session
        if let Some(splade) = self.splade_encoder.get().and_then(|opt| opt.as_ref()) {
            splade.clear_session();
            tracing::info!(
                idle_minutes = elapsed.as_secs() / 60,
                "Cleared SPLADE session after idle timeout"
            );
        }
    }

