                sqlx::query_as("SELECT COUNT(*), COUNT(DISTINCT target_type_name) FROM type_edges")
                    .fetch_one(&self.pool)
                    .await?;

            Ok(TypeEdgeStats {
                total_edges: total_edges as u64,
                unique_types: unique_types as u64,
