pub fn describe_command(args: &[String]) -> (String, Option<String>) {
    use clap::CommandFactory;

    // args[0] is the binary name
    let cmd = args.get(1).map(|s| s.as_str()).unwrap_or("unknown");

    // If it's a bare query (no subcommand), it's a search
    if !cmd.starts_with('-') && !cmd.is_empty() {
        // Check if it's a known subcommand by querying clap's registry.
        // Also recognizes "help" which clap adds automatically.
        let clap_app = super::definitions::Cli::command();
        let is_subcommand = clap_app.get_subcommands().any(|sc| sc.get_name() == cmd);

        if is_subcommand {
            // It's a subcommand -- look for query in remaining args
            let query = args.iter().skip(2).find(|a| !a.starts_with('-')).cloned();
            return (cmd.to_string(), query);
        }

        // Bare query -- it's a search
        return ("search".to_string(), Some(cmd.to_string()));
    }

    (cmd.to_string(), None)
}

pub(crate) fn cmd_reconstruct(
    ctx: &crate::cli::CommandContext<'_, cqs::store::ReadOnly>,
    path: &str,
    json: bool,
) -> Result<()> {
    let _span = tracing::info_span!("cmd_reconstruct", %path).entered();
    let store = &ctx.store;
    let root = &ctx.root;

    // Normalize the path relative to project root
    let rel_path = if std::path::Path::new(path).is_absolute() {
        match std::path::Path::new(path).strip_prefix(root) {
            Ok(rel) => cqs::normalize_path(rel),
            Err(_) => cqs::normalize_path(std::path::Path::new(path)),
        }
    } else {
        cqs::normalize_path(std::path::Path::new(path))
    };

    let chunks = store.get_chunks_by_origin(&rel_path)?;
    if chunks.is_empty() {
        bail!(
            "No indexed chunks found for '{}'. Run `cqs index` first.",
            path
        );
    }

    if json {
        let output = ReconstructOutput {
            file: rel_path.clone(),
            chunks: chunks.len(),
            lines: chunks.last().map(|c| c.line_end).unwrap_or(0),
            content: assemble(&chunks),
        };
        println!("{}", serde_json::to_string_pretty(&output)?);
    } else {
        print!("{}", assemble(&chunks));
    }

    Ok(())
}

