fn atomic_replace_preserves_written_bytes_over_flush() {
        // Regression guard for the DS-V1.25-4 shape: data written via
        // BufWriter but never synced should still end up in the final
        // file because atomic_replace fsyncs the temp before rename.
        let dir = tempfile::TempDir::new().unwrap();
        let tmp = dir.path().join(".ids.tmp");
        let final_path = dir.path().join("ids");
        {
            let f = std::fs::File::create(&tmp).unwrap();
            let mut w = std::io::BufWriter::new(f);
            w.write_all(b"0:a\n1:b\n").unwrap();
            w.flush().unwrap();
            // No explicit sync_all — atomic_replace should do it.
        }
        atomic_replace(&tmp, &final_path).unwrap();
        let got = std::fs::read_to_string(&final_path).unwrap();
        assert_eq!(got, "0:a\n1:b\n");
    }

pub(super) fn file_set(&self) -> Result<HashSet<PathBuf>> {
        self.check_index_staleness();
        {
            let cached = self.file_set.borrow();
            if let Some(fs) = cached.as_ref() {
                return Ok(fs.clone());
            }
        }
        let _span = tracing::info_span!("batch_file_set").entered();
        let exts: Vec<&str> = cqs::language::REGISTRY.supported_extensions().collect();
        let files = cqs::enumerate_files(&self.root, &exts, false)?;
        let set: HashSet<PathBuf> = files.into_iter().collect();
        let result = set.clone();
        *self.file_set.borrow_mut() = Some(set);
        Ok(result)
    }

fn atomic_replace_missing_tmp_returns_error() {
        let dir = tempfile::TempDir::new().unwrap();
        let tmp = dir.path().join("does_not_exist.tmp");
        let final_path = dir.path().join("config.toml");

        let err = atomic_replace(&tmp, &final_path).unwrap_err();
        assert_eq!(err.kind(), io::ErrorKind::NotFound);
        assert!(!final_path.exists());
    }

fn copy_file_atomic(src: &Path, dst: &Path) -> Result<(), StoreError> {
    let dir = dst.parent().unwrap_or(Path::new("."));
    let name = dst
        .file_name()
        .map(|s| s.to_string_lossy().into_owned())
        .unwrap_or_else(|| "backup.tmp".to_string());
    let suffix = crate::temp_suffix();
    let pid = std::process::id();
    let tmp_path = dir.join(format!(".{}.{}.{:016x}.tmp", name, pid, suffix));

    if let Err(e) = std::fs::copy(src, &tmp_path) {
        let _ = std::fs::remove_file(&tmp_path);
        return Err(StoreError::Io(e));
    }

    if let Err(e) = crate::fs::atomic_replace(&tmp_path, dst) {
        let _ = std::fs::remove_file(&tmp_path);
        return Err(StoreError::Io(e));
    }
    Ok(())
}

