fn flush_type_edges(store: &Store, edges: &[(PathBuf, Vec<cqs::parser::ChunkTypeRefs>)]) -> bool {
    if edges.is_empty() {
        return true;
    }
    tracing::info!(files = edges.len(), "Periodic flush: deferred type edges");
    match store.upsert_type_edges_for_files(edges) {
        Ok(()) => true,
        Err(e) => {
            // EH-11: leave the buffer intact for retry rather than silently
            // dropping all deferred edges on transient failure.
            tracing::warn!(
                files = edges.len(),
                error = %e,
                "Periodic flush of deferred type edges failed, retaining for retry"
            );
            false
        }
    }
}

pub fn get_type_graph(&self) -> Result<TypeGraph, StoreError> {
        let _span = tracing::info_span!("get_type_graph").entered();

        self.rt.block_on(async {
            const MAX_TYPE_GRAPH_EDGES: usize = 500_000;
            let rows: Vec<(String, String)> = sqlx::query_as(
                "SELECT c.name, te.target_type_name
                 FROM type_edges te
                 JOIN chunks c ON te.source_chunk_id = c.id
                 LIMIT ?1",
            )
            .bind(MAX_TYPE_GRAPH_EDGES as i64)
            .fetch_all(&self.pool)
            .await?;

            if rows.len() >= MAX_TYPE_GRAPH_EDGES {
                tracing::warn!(
                    cap = MAX_TYPE_GRAPH_EDGES,
                    "Type graph hit edge cap, results may be incomplete"
                );
            }

            let mut forward: HashMap<String, Vec<String>> = HashMap::new();
            let mut reverse: HashMap<String, Vec<String>> = HashMap::new();

            for (chunk_name, type_name) in rows {
                reverse
                    .entry(type_name.clone())
                    .or_default()
                    .push(chunk_name.clone());
                forward.entry(chunk_name).or_default().push(type_name);
            }

            Ok(TypeGraph { forward, reverse })
        })
    }

pub fn build(embeddings: Vec<(String, Embedding)>, dim: usize) -> Result<Self, CagraError> {
        let _span = tracing::debug_span!("cagra_build").entered();
        let (id_map, flat_data, n_vectors) = crate::hnsw::prepare_index_data(embeddings, dim)
            .map_err(|e| CagraError::Build(e.to_string()))?;

        tracing::info!(n_vectors, "Building CAGRA index");

        let resources = cuvs::Resources::new().map_err(|e| CagraError::Cuvs(e.to_string()))?;

        let dataset = Array2::from_shape_vec((n_vectors, dim), flat_data)
            .map_err(|e| CagraError::Cuvs(format!("Failed to create array: {}", e)))?;

        let build_params = cagra_build_params()?;

        let index = cuvs::cagra::Index::build(&resources, &build_params, &dataset)
            .map_err(|e| CagraError::Cuvs(e.to_string()))?;

        tracing::info!("CAGRA index built successfully");

        Ok(Self {
            dim,
            gpu: Mutex::new(GpuState { resources, index }),
            id_map,
            poisoned: AtomicBool::new(false),
        })
    }

