             means a classifier regressed — see #946.)"
        );
    }

    let suggestions = cqs::suggest::suggest_notes(&ctx.store(), &ctx.root)?;

    let json_val: Vec<_> = suggestions
        .iter()
        .map(|s| {
            serde_json::json!({
                "text": s.text,
                "sentiment": s.sentiment,
                "mentions": s.mentions,
                "reason": s.reason,
            })
        })
        .collect();

    Ok(serde_json::json!({
        "suggestions": json_val,
        "total": suggestions.len(),
        "applied": false,
    }))
}

