def stratify(chunks: list[dict], n: int, seed: int = 0) -> list[dict]:
    """Pick n chunks with roughly balanced language coverage."""
    rng = random.Random(seed)
    by_lang: dict[str, list[dict]] = defaultdict(list)
    for c in chunks:
        by_lang[c["language"]].append(c)
    langs = list(by_lang.keys())
    rng.shuffle(langs)
    picked: list[dict] = []
    # Round-robin across languages.
    cursor = {lang: 0 for lang in langs}
    idx_lang = {lang: 0 for lang in langs}
    for lang in langs:
        rng.shuffle(by_lang[lang])
    while len(picked) < n and langs:
        progress = False
        for lang in langs:
            if idx_lang[lang] < len(by_lang[lang]):
                picked.append(by_lang[lang][idx_lang[lang]])
                idx_lang[lang] += 1
                progress = True
                if len(picked) >= n:
                    break
        if not progress:
            break
    return picked

fn detect_heredoc_language_hcl(node: tree_sitter::Node, source: &str) -> Option<&'static str> {
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        if child.kind() == "heredoc_identifier" {
            let ident = source[child.byte_range()].trim().to_uppercase();
            if SHELL_HEREDOC_IDS_HCL.contains(&ident.as_str()) {
                tracing::debug!(identifier = %ident, "HCL heredoc identified as shell");
                return None; // Use default bash
            }
            if ident == "PYTHON" || ident == "PY" {
                tracing::debug!(identifier = %ident, "HCL heredoc identified as python");
                return Some("python");
            }
            tracing::debug!(identifier = %ident, "HCL heredoc identifier not recognized, skipping");
            return Some("_skip");
        }
    }
    // No heredoc_identifier found — might be a template_literal, skip
    Some("_skip")
}

