pub fn into_readonly(self) -> Store<ReadOnly> {
        // `Store<Mode>` implements `Drop`, so we cannot move fields out with
        // normal assignment. Use `ManuallyDrop` + `ptr::read` to transfer
        // ownership field-by-field; the source is forgotten so its Drop
        // doesn't run twice. Safe because we initialize every field of the
        // returned `Store<ReadOnly>` exactly once.
        let me = std::mem::ManuallyDrop::new(self);
        unsafe {
            Store {
                pool: std::ptr::read(&me.pool),
                rt: std::ptr::read(&me.rt),
                dim: me.dim,
                closed: std::ptr::read(&me.closed),
                notes_summaries_cache: std::ptr::read(&me.notes_summaries_cache),
                note_boost_cache: std::ptr::read(&me.note_boost_cache),
                call_graph_cache: std::ptr::read(&me.call_graph_cache),
                test_chunks_cache: std::ptr::read(&me.test_chunks_cache),
                chunk_type_map_cache: std::ptr::read(&me.chunk_type_map_cache),
                _mode: PhantomData,
            }
        }
    }

def generate_identifier_queries(chunks, target=45):
    """Generate identifier lookup queries — literal name searches."""
    # Pick diverse functions/structs/enums across modules
    by_type = {}
    for c in chunks:
        ct = c["chunk_type"]
        if ct in ("function", "method", "struct", "enum", "trait", "constant"):
            by_type.setdefault(ct, []).append(c)

    queries = []
    selected = set()

    for ct, pool in by_type.items():
        random.shuffle(pool)
        suffix = {"function": "function", "method": "method", "struct": "struct",
                  "enum": "enum", "trait": "trait", "constant": "constant"}
        for c in pool:
            if len(queries) >= target:
                break
            if c["name"] in selected:
                continue
            # Skip very short names (likely ambiguous)
            if len(c["name"]) < 4:
                continue

            query_text = f"{c['name']}"
            rank = validate_query(query_text, c["name"])
            if rank and rank <= 5:
                selected.add(c["name"])
                queries.append({
                    "query": query_text,
                    "category": "identifier_lookup",
                    "primary_answer": {"name": c["name"], "file": c["origin"]},
                    "rank": rank,
                })
                if len(queries) % 10 == 0:
                    print(f"  identifier: {len(queries)}/{target}", file=sys.stderr)

    return queries[:target]

