def stratify(chunks: list[dict], n: int, seed: int = 0) -> list[dict]:
    """Pick n chunks with roughly balanced language coverage."""
    rng = random.Random(seed)
    by_lang: dict[str, list[dict]] = defaultdict(list)
    for c in chunks:
        by_lang[c["language"]].append(c)
    langs = list(by_lang.keys())
    rng.shuffle(langs)
    picked: list[dict] = []
    # Round-robin across languages.
    cursor = {lang: 0 for lang in langs}
    idx_lang = {lang: 0 for lang in langs}
    for lang in langs:
        rng.shuffle(by_lang[lang])
    while len(picked) < n and langs:
        progress = False
        for lang in langs:
            if idx_lang[lang] < len(by_lang[lang]):
                picked.append(by_lang[lang][idx_lang[lang]])
                idx_lang[lang] += 1
                progress = True
                if len(picked) >= n:
                    break
        if not progress:
            break
    return picked

pub enum QueryCategory {
    /// Looking for a specific function/type by name ("search_filtered", "HashMap::new")
    IdentifierLookup,
    /// Searching for code by structure ("functions that return Result", "structs with Display")
    Structural,
    /// Searching for code by behavior ("validates user input", "retries with backoff")
    Behavioral,
    /// Searching for abstract concepts ("dependency injection", "observer pattern")
    Conceptual,
    /// Queries requiring multiple signals ("find where errors are logged and retried")
    MultiStep,
    /// Queries with negation ("sort without allocating", "parse but not validate")
    Negation,
    /// Queries constrained by chunk type ("all test functions", "every enum")
    TypeFiltered,
    /// Queries mentioning multiple languages ("Python equivalent of map in Rust")
    CrossLanguage,
    /// No clear category — use default strategy
    Unknown,
}

