pub(super) fn file_set(&self) -> Result<HashSet<PathBuf>> {
        self.check_index_staleness();
        {
            let cached = self.file_set.borrow();
            if let Some(fs) = cached.as_ref() {
                return Ok(fs.clone());
            }
        }
        let _span = tracing::info_span!("batch_file_set").entered();
        let exts: Vec<&str> = cqs::language::REGISTRY.supported_extensions().collect();
        let files = cqs::enumerate_files(&self.root, &exts, false)?;
        let set: HashSet<PathBuf> = files.into_iter().collect();
        let result = set.clone();
        *self.file_set.borrow_mut() = Some(set);
        Ok(result)
    }

fn enumerate_files(root: &Path) -> Result<Vec<PathBuf>> {
    let root = root.canonicalize()?;  // Resolve symlinks in root path

    let files: Vec<PathBuf> = WalkDir::new(&root)
        .follow_links(false)  // Don't follow symlinks (security)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.file_type().is_file())
        .filter(|e| {
            // Skip files over size limit
            e.metadata().map(|m| m.len() <= MAX_FILE_SIZE).unwrap_or(false)
        })
        .filter(|e| {
            // Only supported extensions
            e.path().extension()
                .and_then(|ext| ext.to_str())
                .and_then(Language::from_extension)
                .is_some()
        })
        .map(|e| {
            // Validate path stays within project root
            let path = e.path().canonicalize().ok()?;
            if path.starts_with(&root) {
                Some(path)
            } else {
                tracing::warn!("Skipping path outside project: {}", e.path().display());
                None
            }
        })
        .flatten()
        .collect();

    Ok(files)
}

