fn post_process_javascript_javascript(
    _name: &mut String,
    chunk_type: &mut ChunkType,
    node: tree_sitter::Node,
    _source: &str,
) -> bool {
    if *chunk_type == ChunkType::Constant || *chunk_type == ChunkType::Variable {
        // Skip declarations inside function bodies — only capture module-level
        if is_inside_function_javascript(node) {
            return false;
        }
        // node is the variable_declarator; check if the value child is a function
        if let Some(value) = node.child_by_field_name("value") {
            let kind = value.kind();
            if kind == "arrow_function" || kind == "function_expression" || kind == "function" {
                return false;
            }
        }
    }
    // constructor() in classes → Constructor
    if *chunk_type == ChunkType::Method && _name == "constructor" {
        *chunk_type = ChunkType::Constructor;
    }
    true
}

pub(in crate::cli::batch) fn dispatch_explain(
    ctx: &BatchContext,
    target: &str,
    tokens: Option<usize>,
) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_explain", target).entered();

    let index = ctx.vector_index()?;
