pub(crate) fn inject_content_into_onboard_json(
    json: &mut serde_json::Value,
    content_map: &std::collections::HashMap<String, String>,
    result: &cqs::OnboardResult,
) {
    // entry_point
    if let Some(ep) = json.get_mut("entry_point") {
        if let Some(content) = content_map.get(&result.entry_point.name) {
            ep["content"] = serde_json::json!(content);
        }
    }
    // call_chain
    if let Some(chain) = json.get_mut("call_chain").and_then(|v| v.as_array_mut()) {
        for (i, entry) in chain.iter_mut().enumerate() {
            if let Some(c) = result.call_chain.get(i) {
                if let Some(content) = content_map.get(&c.name) {
                    entry["content"] = serde_json::json!(content);
                }
            }
        }
    }
    // callers
    if let Some(callers) = json.get_mut("callers").and_then(|v| v.as_array_mut()) {
        for (i, entry) in callers.iter_mut().enumerate() {
            if let Some(c) = result.callers.get(i) {
                if let Some(content) = content_map.get(&c.name) {
                    entry["content"] = serde_json::json!(content);
                }
            }
        }
    }
}

pub(in crate::cli::batch) fn dispatch_suggest(
    ctx: &BatchContext,
    apply: bool,
) -> Result<serde_json::Value> {
    let _span = tracing::info_span!("batch_suggest", apply).entered();

    if apply {
        anyhow::bail!(
            "suggest --apply requires a writable store; run `cqs suggest --apply` outside \
             the daemon. (Commands::Suggest is BatchSupport::Cli; reaching this branch \
             means a classifier regressed — see #946.)"
        );
    }

    let suggestions = cqs::suggest::suggest_notes(&ctx.store(), &ctx.root)?;

    let json_val: Vec<_> = suggestions
        .iter()
        .map(|s| {
            serde_json::json!({
                "text": s.text,
                "sentiment": s.sentiment,
                "mentions": s.mentions,
                "reason": s.reason,
            })
        })
        .collect();

    Ok(serde_json::json!({
        "suggestions": json_val,
        "total": suggestions.len(),
        "applied": false,
    }))
}

pub(crate) fn build_explain_output(data: &ExplainData, root: &Path) -> ExplainOutput {
    let _span = tracing::info_span!("build_explain_output", name = %data.chunk.name).entered();
    let chunk = &data.chunk;
    ExplainOutput {
        name: chunk.name.clone(),
        file: cqs::rel_display(&chunk.file, root).to_string(),
        line_start: chunk.line_start,
        line_end: chunk.line_end,
        chunk_type: chunk.chunk_type.to_string(),
        language: chunk.language.to_string(),
        signature: chunk.signature.clone(),
        content: data.content.clone(),
        callers: data.callers.iter().map(|c| CallerEntry {
            name: c.name.clone(),
            file: normalize_path(&c.file).to_string(),
            line_start: c.line,
        }).collect(),
        callees: data.callees.iter().map(|(n, line)| CalleeEntry {
            name: n.clone(),
            line_start: *line,
        }).collect(),
        caller_count: data.caller_count,
        callee_count: data.callee_count,
        similar: data.similar.iter().map(|(idx, score)| SimilarEntry {
            name: data.similar_chunks.get(*idx).map(|c| c.chunk.name.clone()).unwrap_or_default(),
            file: data.similar_chunks.get(*idx).map(|c| cqs::rel_display(&c.chunk.file, root).to_string()).unwrap_or_default(),
            score: *score,
        }).collect(),
        type_deps: data.type_deps.clone(),
    }
}

pub fn prune_orphan_sparse_vectors(&self) -> Result<usize, StoreError> {
        let _span = tracing::debug_span!("prune_orphan_sparse_vectors").entered();
        self.rt.block_on(async {
            let (_guard, mut tx) = self.begin_write().await?;
            let result = sqlx::query(
                "DELETE FROM sparse_vectors WHERE chunk_id NOT IN \
                 (SELECT DISTINCT id FROM chunks)",
            )
            .execute(&mut *tx)
            .await?;
            // If any rows were actually deleted, bump the SPLADE generation
            // so stale on-disk indexes get invalidated. A prune that removes
            // zero rows leaves sparse_vectors byte-identical, so the existing
            // generation is still valid and no bump is needed.
            let affected = result.rows_affected();
            if affected > 0 {
                bump_splade_generation_tx(&mut tx).await?;
                tracing::warn!(
                    rows = affected,
                    "prune_orphan_sparse_vectors deleted rows that should have been caught by \
                     the v19 FK cascade — either FK enforcement is disabled or this database was \
                     manipulated directly. Investigate."
                );
            }
            tx.commit().await?;
            Ok(affected as usize)
        })
    }

