def chunk_matches(result: dict, gold: dict) -> bool:
    """Origin + name + line_start identity. Chunk ids drift across reindexes
    but origin/name/line_start stay stable for the same logical chunk."""
    return (
        result.get("file") == gold.get("origin")
        and result.get("name") == gold.get("name")
        and result.get("line_start") == gold.get("line_start")
    )

pub fn get_types_used_by(&self, chunk_name: &str) -> Result<Vec<TypeUsage>, StoreError> {
        let _span = tracing::debug_span!("get_types_used_by", chunk_name).entered();
        tracing::debug!("querying types used by chunk");

        self.rt.block_on(async {
            let rows: Vec<(String, String)> = sqlx::query_as(
                "SELECT DISTINCT te.target_type_name, te.edge_kind
                 FROM type_edges te
                 JOIN chunks c ON te.source_chunk_id = c.id
                 WHERE c.name = ?1
                 ORDER BY te.edge_kind, te.target_type_name",
            )
            .bind(chunk_name)
            .fetch_all(&self.pool)
            .await?;

            Ok(rows
                .into_iter()
                .map(|(type_name, edge_kind)| TypeUsage {
                    type_name,
                    edge_kind,
                })
                .collect())
        })
    }

